import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const API = 'http://localhost:4000';

function useTruckStats() {
  const [stats, setStats] = useState(null);
  useEffect(() => {
    fetch(`${API}/api/trips`)
      .then(r => r.json())
      .then(trips => {
        if (!Array.isArray(trips)) return;
        const now = new Date();
        const month = now.getMonth();
        const year = now.getFullYear();
        const thisMonth = trips.filter(t => {
          const d = new Date(t.date || t.trip_date || t.created_at);
          return d.getMonth() === month && d.getFullYear() === year;
        });
        const trucks = [...new Set(trips.map(t => t.truck_number || t.truck).filter(Boolean))];
        const revenue = thisMonth.reduce((sum, t) => sum + parseFloat(t.freight_amount || t.amount || 0), 0);
        setStats({ total: trips.length, thisMonth: thisMonth.length, trucks: trucks.length, revenue });
      })
      .catch(() => setStats({ error: true }));
  }, []);
  return stats;
}

export default function HomePage() {
  const navigate   = useNavigate();
  const truckStats = useTruckStats();

  return (
    <div>
      {/* Header */}
      <div style={s.pageHead}>
        <div>
          <div style={s.pageTitle}>Operations Overview</div>
          <div style={s.pageSub}>Maruti Group · Birgunj Transport Division</div>
        </div>
        <div style={s.qaRow}>
          <button style={s.qaBtn} onClick={() => navigate('/trucks')}>+ New Trip</button>
          <button style={{ ...s.qaBtn, ...s.qaBtnOutline }} onClick={() => navigate('/diesel')}>+ Add Diesel</button>
          <button style={{ ...s.qaBtn, ...s.qaBtnOutline }} onClick={() => navigate('/scrap')}>+ Log Scrap</button>
        </div>
      </div>

      {/* Stats */}
      <div style={s.statsStrip}>
        <StatItem label="Trips This Month"   value={truckStats ? (truckStats.error ? '—' : truckStats.thisMonth) : '…'} />
        <div style={s.statDivider} />
        <StatItem label="Total Trips"        value={truckStats ? (truckStats.error ? '—' : truckStats.total)     : '…'} />
        <div style={s.statDivider} />
        <StatItem label="Active Trucks"      value={truckStats ? (truckStats.error ? '—' : truckStats.trucks)    : '…'} />
        <div style={s.statDivider} />
        <StatItem
          label="Revenue This Month"
          value={truckStats ? (truckStats.error ? '—' : `₹${truckStats.revenue.toLocaleString('en-IN')}`) : '…'}
          accent
        />
      </div>

      {/* Modules */}
      <div style={s.sectionLabel}>Modules</div>
      <div style={s.grid}>
        {modules.map(m => (
          <ModuleCard key={m.to} {...m} onClick={() => navigate(m.to)} />
        ))}
      </div>
    </div>
  );
}

function StatItem({ label, value, accent }) {
  return (
    <div style={s.statItem}>
      <div style={s.statLabel}>{label}</div>
      <div style={{ ...s.statValue, color: accent ? '#d97706' : '#0f2318' }}>{value}</div>
    </div>
  );
}

function ModuleCard({ label, desc, status, onClick }) {
  const [hovered, setHovered] = useState(false);
  const isActive = status === 'Active';

  return (
    <div
      style={{
        ...s.card,
        opacity: isActive ? 1 : 0.55,
        borderColor: hovered && isActive ? '#d97706' : '#e8e3db',
        boxShadow: hovered && isActive ? '0 4px 20px rgba(15,35,24,0.08)' : 'none',
        cursor: isActive ? 'pointer' : 'default',
      }}
      onClick={isActive ? onClick : undefined}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div style={s.cardTop}>
        <div style={s.cardLabel}>
          {label}
          {!isActive && <span style={s.lockIcon}>🔒</span>}
        </div>
        {isActive && <span style={s.badgeActive}>Active</span>}
      </div>
      <div style={s.cardDesc}>{desc}</div>
      {isActive && (
        <div style={{ ...s.cardCta, color: hovered ? '#d97706' : '#0f2318' }}>
          Open module →
        </div>
      )}
    </div>
  );
}

const modules = [
  { to: '/trucks',      label: 'Truck Management',    desc: 'Trip entries, admin view, freight rates & settings.',          status: 'Active'      },
  { to: '/scrap',       label: 'Scrap Management',    desc: 'Collected vs sold inventory, stock balance, monthly summary.', status: 'Coming Soon' },
  { to: '/diesel',      label: 'Diesel Inventory',    desc: 'Purchase log, trip consumption tracking, low-stock alerts.',  status: 'Coming Soon' },
  { to: '/dashboard',   label: 'Dashboard & Insights',desc: 'Revenue, expenses, per-truck KPIs and trend charts.',          status: 'Coming Soon' },
  { to: '/drivers',     label: 'Driver Advances',     desc: 'Cash advances, expense claims, running balance per driver.',  status: 'Coming Soon' },
  { to: '/maintenance', label: 'Maintenance Log',     desc: 'Service history, next service due dates, parts & cost.',       status: 'Coming Soon' },
  { to: '/customers',   label: 'Customer Ledger',     desc: 'Outstanding freight, payment records, customer balances.',    status: 'Coming Soon' },
];

const s = {
  pageHead:  { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28, flexWrap: 'wrap', gap: 16 },
  pageTitle: { fontSize: 22, fontWeight: 800, color: '#0f2318', letterSpacing: '-0.3px' },
  pageSub:   { fontSize: 12, color: '#a89880', marginTop: 4, fontWeight: 500 },

  qaRow: { display: 'flex', gap: 8, flexWrap: 'wrap' },
  qaBtn: {
    padding: '9px 18px',
    background: '#0f2318',
    color: '#fff',
    border: '1.5px solid #0f2318',
    borderRadius: 8,
    fontSize: 12,
    fontWeight: 700,
    cursor: 'pointer',
    letterSpacing: '0.02em',
    fontFamily: "'Plus Jakarta Sans', sans-serif",
  },
  qaBtnOutline: {
    background: 'transparent',
    color: '#0f2318',
  },

  statsStrip: {
    background: '#fff',
    border: '1px solid #e8e3db',
    borderRadius: 12,
    display: 'flex',
    alignItems: 'stretch',
    marginBottom: 32,
    overflow: 'hidden',
  },
  statItem:   { flex: 1, padding: '20px 24px' },
  statLabel:  { fontSize: 11, fontWeight: 600, color: '#a89880', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 8 },
  statValue:  { fontSize: 28, fontWeight: 800, lineHeight: 1, letterSpacing: '-0.5px' },
  statDivider:{ width: 1, background: '#e8e3db', flexShrink: 0 },

  sectionLabel: { fontSize: 11, fontWeight: 700, color: '#a89880', textTransform: 'uppercase', letterSpacing: '0.09em', marginBottom: 14 },

  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 14 },
  card: {
    background: '#fff',
    borderRadius: 10,
    border: '1px solid #e8e3db',
    padding: '18px 20px 20px',
    transition: 'border-color 0.2s, box-shadow 0.2s, opacity 0.2s',
  },
  cardTop:    { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 },
  cardLabel:  { fontSize: 14, fontWeight: 700, color: '#0f2318', display: 'flex', alignItems: 'center', gap: 7 },
  lockIcon:   { fontSize: 11, opacity: 0.6 },
  cardDesc:   { fontSize: 12, color: '#8a7a6a', lineHeight: 1.65 },
  cardCta:    { fontSize: 12, fontWeight: 700, marginTop: 12, transition: 'color 0.2s', letterSpacing: '0.01em' },

  badgeActive: {
    fontSize: 10,
    fontWeight: 700,
    padding: '3px 9px',
    borderRadius: 20,
    background: '#f0fdf4',
    color: '#14532d',
    border: '1px solid #bbf7d0',
    letterSpacing: '0.04em',
    textTransform: 'uppercase',
  },
};
